"use client";

import { useEffect, useState } from "react";
import { useRouter } from "next/navigation";
import { getDashboardPathForRole } from "../../../lib/auth";

export default function PatientDashboard() {
  const [records, setRecords] = useState<any[]>([]);
  const router = useRouter();

  useEffect(() => {
    const init = async () => {
      const stored = localStorage.getItem("user");

      if (!stored) {
        router.replace("/auth/login");
        return;
      }

      const user = JSON.parse(stored);

      // Only PATIENTs can access this dashboard
      if (user.role !== "PATIENT") {
        const target = getDashboardPathForRole(user.role);
        router.replace(target);
        return;
      }

      const res = await fetch(
        `http://localhost:5000/api/patient/${user.patientId}/history`,
        {
          headers: {
            Authorization: `Bearer ${localStorage.getItem("token")}`,
          },
        }
      );

      const data = await res.json();
      setRecords(data);
    };

    init();
  }, []);

  return (
    <div>
      <h1 className="text-xl font-bold mb-4">My Medical History</h1>

      <div className="space-y-4">
        {records.map((r, i) => (
          <div key={i} className="bg-white p-4 rounded shadow">
            <p><strong>Disease:</strong> {r.disease}</p>
            <p><strong>Hospital:</strong> {r.hospitalName}</p>
            <p><strong>Date:</strong> {new Date(r.date).toDateString()}</p>
          </div>
        ))}
      </div>
    </div>
  );
}